104	    std::string_view name;
105	#if __GNUC__ || __clang__
106	    name = __PRETTY_FUNCTION__;
107	    std::size_t start = name.find('=') + 2;
108	    std::size_t end = name.size() - 1;
109	    name = std::string_view{ name.data() + start, end - start };
110	    start = name.find("::");
111	#elif _MSC_VER
112	    name = __FUNCSIG__;
113	    std::size_t start = name.find('<') + 1;
114	    std::size_t end = name.rfind(">(");
115	    name = std::string_view{ name.data() + start, end - start };
116	    start = name.rfind("::");
117	#endif
