171	    constexpr virtual inline std::span<const FeatureT> get_supported_features() const = 0;
172	
173	    virtual ~ImplBase() = default;
174	
175	public:
176	    inline bool check_if_all_features_are_supported(const std::vector<FeatureT> &required_features) {
177	        for (const auto &required_feature : required_features) {
178	            bool is_supported = false;
179	            for (const auto &supported_feature : get_supported_features()) {
