165	#define MLA_NUM_SPLITS_SWITCH(NUM_SPLITS, NAME, ...)       \
166	    [&] {                                                  \
167	        if (NUM_SPLITS <= 32) {                            \
168	            constexpr static int NAME = 32;                \
169	            return __VA_ARGS__();                          \
170	        } else if (NUM_SPLITS <= 64) {                     \
171	            constexpr static int NAME = 64;                \
172	            return __VA_ARGS__();                          \
173	        } else if (NUM_SPLITS <= 96) {                     \
174	            constexpr static int NAME = 96;                \
175	            return __VA_ARGS__();                          \
176	        } else if (NUM_SPLITS <= 128) {                    \
177	            constexpr static int NAME = 128;               \
178	            return __VA_ARGS__();                          \
179	        } else if (NUM_SPLITS <= 160) {                    \
180	            constexpr static int NAME = 160;               \
181	            return __VA_ARGS__();                          \
182	        } else {                                           \
183	            FLASH_ASSERT(false);                           \
184	        }                                                  \
185	    }()
186	
