188	template<typename ElementT>
189	void run_flash_mla_combine_kernel(CombineParams &params) {
190	    static constexpr int HEAD_DIM_V = 512;  // Since only this head dimension is supported by Flash MLA
191	    FLASH_ASSERT(params.d_v == HEAD_DIM_V);
192	    MLA_NUM_SPLITS_SWITCH(params.num_sm_parts, NUM_SPLITS, [&] {
193	        constexpr int BLOCK_SIZE_M = 8;
194	        constexpr int NUM_THREADS = BLOCK_SIZE_M*32;
195	        constexpr size_t smem_size = BLOCK_SIZE_M*(NUM_SPLITS+1)*sizeof(float);
196	        auto combine_kernel = &flash_fwd_mla_combine_kernel<ElementT, HEAD_DIM_V, BLOCK_SIZE_M, NUM_SPLITS, NUM_THREADS>;
197	        CHECK_CUDA(cudaFuncSetAttribute(combine_kernel, cudaFuncAttributeMaxDynamicSharedMemorySize, smem_size));
198	        // Use cudaLaunchKernelEx to enable PDL (Programmatic Dependent Launch)
199	        cudaLaunchAttribute attribute[1];
200	        attribute[0].id = cudaLaunchAttributeProgrammaticStreamSerialization;
201	        attribute[0].val.programmaticStreamSerializationAllowed = 1;
202	        cudaLaunchConfig_t combine_kernel_config = {
203	            dim3(params.b * params.s_q, 1, ku::ceil_div(params.h_q, BLOCK_SIZE_M)),
204	            dim3(NUM_THREADS, 1, 1),
205	            0,
206	            params.stream,
207	            attribute,
208	            1
209	        };
210	        CHECK_CUDA(cudaLaunchKernelEx(&combine_kernel_config, combine_kernel, params));
211	    });
212	    CHECK_CUDA_KERNEL_LAUNCH();
213	}
