11	// Check whether the given tensor or optional tensor satisfies the given condition
12	// If tensor_or_opt is a tensor, check_fn is applied directly
13	// If tensor_or_opt is an optional tensor, check_fn is applied only when the optional has value
14	template<typename T>
15	static inline bool _check_optional_tensor(const T& tensor_or_opt, const std::function<bool(const at::Tensor&)>& check_fn) {
16	    if constexpr (std::is_same<T, at::Tensor>::value) {
17	        return check_fn(tensor_or_opt);
18	    } else {
19	        if (tensor_or_opt.has_value()) {
20	            return check_fn(tensor_or_opt.value());
21	        } else {
22	            return true;
23	        }
24	    }
25	}
